(window.webpackJsonp=window.webpackJsonp||[]).push([[374],{1001:function(r,n){r.exports='\x3c!-- \r\ntitle: 10-CSS基础\r\nsort: \r\n--\x3e \r\n# CSS基础\r\n\r\n## First\r\n\r\n![image-20200721103637737](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200721103644.png)\r\n\r\n```css\r\nbody\r\n{\r\n    background-color:#d0e4fe;\r\n    /*这是个注释*/\r\n}\r\nh1\r\n{\r\n    color:orange;\r\n    text-align:center;\r\n}\r\np\r\n{\r\n    font-family:"Times New Roman";\r\n    font-size:20px;\r\n}\r\n```\r\n\r\n## 基础语法\r\n\r\n- id选择器`#test`\r\n\r\n- class选择器`.test2`\r\n\r\n  > 可以使用`p.test2`\r\n\r\n### 创建css\r\n\r\n- 外部样式表\r\n\r\n  ```html\r\n  <head>\r\n  <link rel="stylesheet" type="text/css" href="mystyle.css">\r\n  </head>\r\n  ```\r\n\r\n- 内部样式表\r\n\r\n  ```html\r\n  <style>\r\n  hr {color:sienna;}\r\n  p {margin-left:20px;}\r\n  body {background-image:url("images/back40.gif");}\r\n  </style>\r\n  ```\r\n\r\n- 内联样式表\r\n\r\n  `<p style="color:sienna;margin-left:20px">这是一个段落。</p>`\r\n\r\n### 背景\r\n\r\n> `background-color`\r\n> `background-image`：背景图像\r\n> `background-repeat`\r\n>\r\n> - `background-repeat:repeat-x`：水平方向平铺\r\n> - `background-repeat:no-repeat`：取消平铺\r\n>\r\n> `background-attachment`\r\n> `background-position`\r\n>\r\n> - `background-position:right top`：位置在右上方\r\n>\r\n> 简写：`body {background:#ffffff url(\'img_tree.png\') no-repeat right top;}`\r\n\r\n## 文本\r\n\r\n- 颜色：`color:red`\r\n\r\n- 对齐方式：`text-align:cneter`\r\n\r\n  > center 中心\r\n  >\r\n  > right\t右侧\r\n  >\r\n  > justify 每一行被展开为宽度相等对其，杂志和报纸。\r\n\r\n- 文本修饰\r\n\r\n  > `a {text-decoration:none;}`：删除链接的下划线\r\n  >\r\n  > 上中下线\r\n  >\r\n  > ```css\r\n  > h1 {text-decoration:overline;}\r\n  > h2 {text-decoration:line-through;}\r\n  > h3 {text-decoration:underline;}\t\t\r\n  > ```\r\n\r\n- 文本转换\r\n\r\n  > 全体大写、小写、首字母大写\r\n  > \r\n  > ```css\r\n  > p.uppercase {text-transform:uppercase;}\r\n  > p.lowercase {text-transform:lowercase;}\r\n  > p.capitalize {text-transform:capitalize;}\r\n  > ```\r\n\r\n- 文本缩进(首行)\r\n\r\n  > `letter-spacing:30px;`：字母与字母之间的间距。\r\n  >\r\n  > `word-spacing:30px;`：单词或中文间距。\r\n\r\n## 字体\r\n\r\n![Serif vs. Sans-serif](https://www.runoob.com/images/serif.gif)\r\n\r\n- 设置字体：`p{font-family:"Times New Roman", Times, serif;}`\r\n\r\n- 字体样式：\r\n\r\n  ```css\r\n  p.normal {font-style:normal;}\r\n  p.italic {font-style:italic;}\r\n  p.oblique {font-style:oblique;}\r\n  \r\n  h1 {font-size:40px;}\r\n  h2 {font-size:30px;}\r\n  p {font-size:14px;}\r\n  \r\n  /* 1em = 16px */\r\n  ```\r\n\r\n\r\n## 链接\r\n\r\n### 样式\r\n\r\n```css\r\na:link {color:#000000;}      /* 未访问链接*/\r\na:visited {color:#00FF00;}  /* 已访问链接 */\r\na:hover {color:#FF00FF;}  /* 鼠标移动到链接上 */\r\na:active {color:#0000FF;}  /* 鼠标点击时 */\r\n```\r\n\r\n### 修饰\t\t\t\r\n\r\n```css\r\na:link {background-color:#B2FF99;}\r\na:visited {background-color:#FFFF85;}\r\na:hover {text-decoration:underline;}\r\na:active {text-decoration:underline;}\r\n```\r\n\r\n## 列表及表格\r\n\r\n### 标记\r\n\r\n```css\r\nul.a {list-style-type: circle;}\r\nul.b {list-style-type: square;}\r\n \r\nol.c {list-style-type: upper-roman;}\r\nol.d {list-style-type: lower-alpha;}\r\n\r\n/* 图像标记 */\r\nul\r\n{\r\n    list-style-image: url(\'sqpurple.gif\');\r\n}\r\n\r\n/* 简写 */\r\nul\r\n{\r\n    list-style: square url("sqpurple.gif");\r\n}\r\n```\r\n\r\n### 表格\r\n\r\n```css\r\n/* 边框 */\r\nable, th, td\r\n{\r\n    border: 1px solid black;\r\n}\r\n\r\ntd\r\n{\r\n    padding:15px;\r\n}\r\n\r\n/* 颜色 */\r\ntable, td, th\r\n{\r\n    border:1px solid green;\r\n}\r\nth\r\n{\r\n    background-color:green;\r\n    color:white;\r\n}\r\n```\r\n\r\n'}}]);